-- 2026-06-01: knee_extensor_mechanism_repair — фазы «Путь» + структурированные критерии перехода.
-- Knee protocols, коммит S1 (ТЗ TZ_PATIENT_PATH_KNEE_PROTOCOLS.md §7).
--
-- Источник: PROTOCOLS досье разрыва разгибательного аппарата колена (разрыв связки надколенника /
-- сухожилия квадрицепса) + PROTOCOLS/_ext_knee_extensor_mechanism_repair.json.
-- Якорь — дата операции. Основная траектория — послеоперационный протокол (5 фаз: защита шва →
-- защищённая флексия → укрепление → переход к бегу → возврат к спорту). Фазы 0 в данных нет —
-- нумерация совпадает с источником (1..5).
--
-- ВАЖНО (для контента): ранние сроки нагрузки, диапазона движений, ношения и снятия ортеза, начала
-- активного разгибания задаёт хирург по тому, насколько прочным получился шов. Поэтому в видимом
-- тексте числовые ограничения по нагрузке и ортезу даны как «по указанию врача», без жёстких цифр.
-- Сроки в подзаголовках — ориентиры, реальный темп индивидуален.
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их СРАЗУ
-- в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки (слот D2).
--
-- Классификация критериев (ТЗ §2.3): авто-проверяемо сегодня только сгибание/разгибание колена
-- (measurement_type='knee_flexion_degrees'/'knee_extension_degrees', source='rom'). Активное
-- разгибание, экстензионный лаг, сила квадрицепса (LSI%), прыжковые/баланс/RTS-тесты система не
-- хранит как самостоятельные замеры → 'instructor_check' с порогом в тексте label (куратор вводит
-- очно). Качественное да/нет от пациента → 'self_report'.
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц (AdminContent = источник истины после
-- деплоя; ручная калибровка не затирается). Прогон тест-цикла createdb→schema→migrations×2 → ок.
-- НЕ трогает acl/другие program_type (разные program_type/phase_id).

BEGIN;

-- =====================================================
-- 1. Фазы knee_extensor_mechanism_repair (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
