-- =====================================================
-- 2. Структурированные критерии перехода knee_extensor_mechanism_repair
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (защита шва → возвращаем сгибание)
  (1, 'weeks_since_surgery_2',  'Прошло 2 недели и более после операции',                              'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'full_passive_extension', 'Колено пассивно полностью выпрямляется (0 градусов)',                  'measurement',      'knee_extension_degrees', 'rom', '<=', 0::numeric, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  -- Фаза 2 → Фаза 3 (возвращаем сгибание → укрепление)
  (2, 'full_passive_extension', 'Колено пассивно полностью выпрямляется (0 градусов)',                  'measurement',      'knee_extension_degrees', 'rom', '<=', 0, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'flexion_90',             'Сгибание колена достигло примерно 90 градусов',                        'measurement',      'knee_flexion_degrees',   'rom', '>=', 90, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'full_weightbearing',     'Получается опираться на ногу полностью без боли',                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'active_extension_0',     'Получается держать ногу прямой за счёт мышцы бедра, без провисания',    'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  -- Фаза 3 → Фаза 4 (укрепление → подготовка к бегу)
  (3, 'flexion_120',            'Сгибание колена достигло примерно 120 градусов',                       'measurement',      'knee_flexion_degrees',   'rom', '>=', 120, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'single_leg_balance_30',  'Получается уверенно стоять на одной ноге около 30 секунд',             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'single_leg_squat_10',    '10 приседаний на одной ноге до прямого угла с хорошей техникой',        'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'quad_strength_70',       'Сила мышцы бедра не менее 70% от здоровой ноги (оценка на 16 неделе)',  'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, TRUE),
  -- Фаза 4 → Фаза 5 (подготовка к бегу → возврат к спорту)
  (4, 'full_rom_no_deficit',    'Колено двигается в полном объёме без ограничения',                     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'no_swelling_pain',       'Нет отёка и боли при нагрузке',                                        'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Нет ли отёка или боли в колене при нагрузке?', 'Оцените состояние после привычной активности', 20::smallint, TRUE),
  (4, 'quad_strength_80',       'Сила мышцы бедра не менее 80% от здоровой ноги (порог для начала бега)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, TRUE),
  (4, 'single_leg_hop_form',    'Уверенный прыжок и мягкое приземление на одной ноге с хорошей техникой', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (4, 'quad_strength_90',       'Сила мышцы бедра не менее 90% от здоровой ноги',                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 50::smallint, TRUE),
  (4, 'y_balance_90',           'Равновесие и контроль ноги не менее 90% от здоровой стороны',          'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 60::smallint, FALSE),
  -- Фаза 5 (возврат к спорту → финальная, переходов дальше нет)
  (5, 'rts_tests_passed',       'Пройдены все проверки готовности к спорту',                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (5, 'quad_strength_90_rts',   'Сила мышцы бедра не менее 90% от здоровой ноги',                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (5, 'no_extension_lag',       'Нога полностью держится прямой без провисания',                        'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (5, 'hop_tests_90',           'Прыжковые тесты не менее 90% от здоровой ноги',                        'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, TRUE),
  (5, 'y_balance_90_rts',       'Равновесие и контроль ноги не менее 90% от здоровой стороны',          'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 50::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'knee_extensor_mechanism_repair' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
